    b_clean: PersistentMemoryByte,
    b_dirty: PersistentMemoryByte,
)
    requires
        b_clean.outstanding_write.is_none(),
        b_clean.state_at_last_flush == 0,
        b_dirty.outstanding_write == Some(42u8),
        b_dirty.state_at_last_flush == 0,
