        ({
            let view = PersistentMemoryRegionView {
                state: seq![b_clean, b_dirty, b_clean, b_clean, b_clean, b_clean, b_clean, b_clean],
            };
            let s = seq![0u8, 42u8, 0u8, 0u8, 0u8, 0u8, 0u8, 0u8];
